  ('promotion-6f0ba476-moex-00056', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-9bdab6d6', 'sub-promotion-6f0ba476-02', NULL, 'single_choice', '依據財政收支劃分法的最新規定，下列何者最符合現行制度？', '["若中央統籌分配款因計算配分公式未能全數分配之餘額，仍屬地方政府收入，中央不得另作 他用", "地方政府當年度分配款若低於修法前1年，只能透過計畫型補助款由中央補足差額", "貨物稅納入統籌分配的比例全面調整為100%，因此地方財政將大幅增強該來源收入", "中央政府可在一般性補助款項金額不足的情況下，透過優先調降該部分以補足他項財源短缺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "0db78bbd5426", "answer_pdf_sha1": "316b075c224f", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "0515", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00057', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-d3ff7f6b', 'sub-promotion-6f0ba476-03', NULL, 'essay', '某經濟體的生產函數為：Y  K1/3L1/3H1/3，其中 為產出，K為實質資本
